import React from 'react';

const TabContent = ({campuses, hostels, misc, onCampusButtonClick }) => (

    <div className="tab-city__content">
      {campuses && <div className="mb-1">
        <p className="mb-0">Корпуса</p>
        {campuses.map(item => (
          <button className="btn btn-primary mr-1 mb-1" onClick={() => onCampusButtonClick(item.id)}>{item.title}</button>
        ))}
      </div>}

      {hostels && <div className="mb-1">
        <p className="mb-0">Общежития</p>
        {hostels.map(item => (
          <button className="btn btn-primary mr-1 mb-1" onClick={() => onCampusButtonClick(item.id)}>{item.title}</button>
        ))}
      </div>}

      {misc && <div className="mb-1">
        <p className="mb-0">Дополнительно</p>
        {misc.map(item => (
          <button className="btn btn-primary mr-1 mb-1" onClick={() => onCampusButtonClick(item.id)}>{item.title}</button>
        ))}
      </div>}

    </div>

);

export default TabContent;
