import React, {useState} from 'react';
import Map from "./Map";
import Panel from "./Panel";
import Tabs from "./Tabs";

const Campuses = ({cities}) => {
  const [mapCenter, setMapCenter] = useState([45.043528, 41.962227]);
  const [selectedCampus, setSelectedCampus] = useState({});
  const [panelIsOpen, setPanelIsOpen] = useState(false);


  const campuses = [].concat.apply([], cities.map(city => city.campuses));
  const hostels = [].concat.apply([], cities.map(city => city.hostels));
  const misc = [].concat.apply([], cities.map(city => city.misc));

  const markers = [...campuses, ...hostels, ...misc].filter(item => item);

  const markersMap = markers.reduce((out, item) => {
    out[item.id] = item;
    return out;
  }, {});

  const onTabClick = (id) => {
    setMapCenter([cities[id].campuses[0].lat, cities[id].campuses[0].lon]);
    setPanelIsOpen(false);
  };

  const onMarkerOrCampusButtonClick = (id) => {
    setMapCenter([markersMap[id].lat, markersMap[id].lon]);
    setSelectedCampus(markersMap[id]);
    setPanelIsOpen(true);
  };

  const onCampusButtonClick = (id) => {
    onMarkerOrCampusButtonClick(id);
  };

  const onMarkerClick = (id) => {
    onMarkerOrCampusButtonClick(id);
  };

  const onClosePanel = () => {
    setPanelIsOpen(false);
  };

  return (
    <>
      <Tabs items={cities} onTabClick={onTabClick} onCampusButtonClick={onCampusButtonClick}/>
      <div className="map-container">
        <Map campuses={markers} selectedCampusId={selectedCampus.id} center={mapCenter} onMarkerClick={onMarkerClick}/>
        <Panel panelIsOpen={panelIsOpen} campus={selectedCampus} onClosePanel={onClosePanel}/>
      </div>
    </>
  )
};

export default Campuses;

