import React, {useState} from 'react';
import TabContent from "./TabContent";

const Tabs = ({ items, onTabClick, onCampusButtonClick }) => {
  const [ active, setActive ] = useState(0);

  const openTab = (e) => {
    setActive(+e.target.dataset.index);
    onTabClick(+e.target.dataset.index);
  };

  return (
    <>
      <div className="tab-city">
        {items.map((n, i) => (
          <button
            className={`tab-city__link ${i === active ? 'tab-city__link--active' : ''}`}
            onClick={openTab}
            data-index={i}
          >{n.title}</button>
        ))}
      </div>
      {items[active] && <TabContent onCampusButtonClick={onCampusButtonClick} {...items[active]} />}
    </>
  );
};

export default Tabs;
